diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 394dfca262e1..22848473c77b 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3011,7 +3011,6 @@ struct DecomposedSelect {
   Value *FalseVal = nullptr;
 };
 } // namespace
-
 /// Look for patterns like
 ///   %outer.cond = select i1 %inner.cond, i1 %alt.cond, i1 false
 ///   %inner.sel = select i1 %inner.cond, i8 %inner.sel.t, i8 %inner.sel.f
@@ -3023,9 +3022,22 @@ static Instruction *foldNestedSelects(SelectInst &OuterSelVal,
                                       InstCombiner::BuilderTy &Builder) {
   // We must start with a `select`.
   DecomposedSelect OuterSel;
-  match(&OuterSelVal,
-        m_Select(m_Value(OuterSel.Cond), m_Value(OuterSel.TrueVal),
-                 m_Value(OuterSel.FalseVal)));
+  OuterSel.Cond = OuterSelVal.getCondition();
+  OuterSel.TrueVal = OuterSelVal.getTrueValue();
+  OuterSel.FalseVal = OuterSelVal.getFalseValue();
+
+  DecomposedSelect InnerSel1;
+  if (match(OuterSel.TrueVal, m_Select(m_Value(InnerSel1.Cond),
+                                       m_Value(InnerSel1.TrueVal),
+                                       m_Value(InnerSel1.FalseVal))) &&
+      match(OuterSel.FalseVal, m_Select(m_Specific(InnerSel1.Cond),
+                                        m_Specific(InnerSel1.FalseVal),
+                                        m_Specific(InnerSel1.TrueVal))) &&
+      OuterSel.Cond->getType() == InnerSel1.Cond->getType() &&
+      OuterSel.TrueVal->hasOneUse() && OuterSel.FalseVal->hasOneUse()) {
+    Value *Cond = Builder.CreateXor(OuterSel.Cond, InnerSel1.Cond);
+    return SelectInst::Create(Cond, InnerSel1.FalseVal, InnerSel1.TrueVal);
+  }

   // Canonicalize inversion of the outermost `select`'s condition.
   if (match(OuterSel.Cond, m_Not(m_Value(OuterSel.Cond))))

